    }
    return defaultValue;
  }
  if (field.value == null) {
    if (nullable) return null;
    throw FormatException('Null field: $name');
  }
  final value = read(field.value);
  if (value == null) {
    throw FormatException('Invalid field: $name');
  }
  return value;
}

